namespace BgCommon.Script.Runtime.Configuration;/// <summary>/// 提供用于构建和配置 <see cref="ScriptConfig"/> 对象的扩展方法和静态方法./// </summary>public static class ConfigBuilder{    /// <summary>    /// 创建并返回一个新的 <see cref="ScriptConfig"/> 实例.    /// </summary>    /// <param name="name">配置文件名称.</param>    /// <param name="directory">文件存储路径.</param>    /// <param name="libraryRefDirectory">引用程序集所在路径.</param>    /// <param name="extension">文件扩展名.</param>    /// <returns>返回初始化后的 <see cref="ScriptConfig"/> 对象.</returns>    public static ScriptConfig BuildScriptConfig(        string name,        string directory,        string libraryRefDirectory,        string? extension = null)    {        ArgumentNullException.ThrowIfNullOrEmpty(name, nameof(name));        return new ScriptConfig(directory, libraryRefDirectory, extension, name);    }    /// <summary>    /// 创建并返回一个新的 <see cref="ScriptConfig"/> 实例.    /// </summary>    /// <param name="name">配置文件名称.</param>    /// <param name="directory">文件存储路径.</param>    /// <param name="libraryRefDirectory">引用程序集所在路径.</param>    /// <param name="extension">文件扩展名.</param>    /// <returns>返回初始化后的 <see cref="TemplateConfig"/> 对象.</returns>    public static TemplateConfig BuildTemplateConfig(        string name,        string directory,        string libraryRefDirectory,        string? extension = null)    {        ArgumentNullException.ThrowIfNullOrEmpty(name, nameof(name));        return new TemplateConfig(directory, libraryRefDirectory, extension, name);    }}